"use client";

import { useEffect, useState, FormEvent } from "react";

const API_BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

type Account = {
  id: string;
  owner: string;
  balance: number;
  createdAt: string;
};

export default function QTradePage() {
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [owner, setOwner] = useState("");
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [amount, setAmount] = useState("100");
  const [err, setErr] = useState<string | null>(null);

  const load = async () => {
    try {
      const res = await fetch(`${API_BASE}/api/qtrade/accounts`);
      const data = await res.json();
      setAccounts(data.items || []);
    } catch {
      setErr("Backend недоступен");
    }
  };

  useEffect(() => {
    load();
  }, []);

  const createAccount = async (e: FormEvent) => {
    e.preventDefault();
    if (!owner.trim()) return;

    await fetch(`${API_BASE}/api/qtrade/accounts`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ owner }),
    });

    setOwner("");
    load();
  };

  const topup = async () => {
    if (!from) return;

    await fetch(`${API_BASE}/api/qtrade/topup`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ accountId: from, amount: Number(amount) }),
    });

    load();
  };

  const transfer = async (e: FormEvent) => {
    e.preventDefault();
    if (!from || !to) return;

    await fetch(`${API_BASE}/api/qtrade/transfer`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ from, to, amount: Number(amount) }),
    });

    load();
  };

  return (
    <main style={{ padding: 24, maxWidth: 900 }}>
      <h1 style={{ fontSize: 26 }}>QTrade</h1>
      <p style={{ color: "#666" }}>
        Счета, пополнение и переводы (MVP).
      </p>

      {err && <p style={{ color: "crimson" }}>{err}</p>}

      <section style={{ marginTop: 20 }}>
        <h2>Создать счёт</h2>
        <form onSubmit={createAccount}>
          <input
            placeholder="Owner"
            value={owner}
            onChange={(e) => setOwner(e.target.value)}
          />
          <button type="submit">Создать</button>
        </form>
      </section>

      <section style={{ marginTop: 20 }}>
        <h2>Операции</h2>

        <form onSubmit={transfer}>
          <select value={from} onChange={(e) => setFrom(e.target.value)}>
            <option value="">From</option>
            {accounts.map((a) => (
              <option key={a.id} value={a.id}>
                {a.owner} ({a.balance})
              </option>
            ))}
          </select>

          <select value={to} onChange={(e) => setTo(e.target.value)}>
            <option value="">To</option>
            {accounts.map((a) => (
              <option key={a.id} value={a.id}>
                {a.owner} ({a.balance})
              </option>
            ))}
          </select>

          <input
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="Amount"
          />

          <div style={{ marginTop: 10 }}>
            <button type="button" onClick={topup}>
              Пополнить
            </button>
            <button type="submit" style={{ marginLeft: 10 }}>
              Перевести
            </button>
          </div>
        </form>
      </section>

      <section style={{ marginTop: 30 }}>
        <h2>Счета</h2>
        {accounts.map((a) => (
          <div key={a.id}>
            {a.owner} — {a.balance}
          </div>
        ))}
      </section>
    </main>
  );
}
